SELECT count(*) FROM char_name, cast_info, title, name, role_type, aka_name, kind_type, movie_info WHERE cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND aka_name.person_id = name.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id;